import bpy
try:
    _NAME = {{name|json}}
    _LOC = {{location|json}}
    _S = float({{size}})
    _T = float({{thickness}})
    _D = float({{density}})
    _C = {{color|json}}

    bpy.ops.mesh.primitive_cube_add(size=1, location=_LOC)
    obj = bpy.context.object; obj.name = _NAME
    obj.scale = (_S, _S, _T)
    bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)
    obj.display_type = 'WIRE'

    mat = bpy.data.materials.new(_NAME + '_fog_mat')
    mat.use_nodes = True
    nt = mat.node_tree
    for n in list(nt.nodes):
        nt.nodes.remove(n)
    out = nt.nodes.new('ShaderNodeOutputMaterial')
    out.location = (400, 0)
    vs = nt.nodes.new('ShaderNodeVolumeScatter')
    vs.location = (200, 0)
    if 'Color' in vs.inputs:
        vs.inputs['Color'].default_value = (_C[0], _C[1], _C[2], 1.0)
    if 'Density' in vs.inputs:
        vs.inputs['Density'].default_value = _D
    if 'Anisotropy' in vs.inputs:
        vs.inputs['Anisotropy'].default_value = 0.0
    nt.links.new(vs.outputs['Volume'], out.inputs['Volume'])
    obj.data.materials.append(mat)
    print('[apply_template] fog_volume 完成: density=' + str(_D))
except Exception as _e:
    import traceback; print('[apply_template] fog_volume 失败:', _e); traceback.print_exc()

import bpy, math
try:
    _NAME = {{name|json}}
    _LOC = {{location|json}}
    _L = float({{length}})
    _W = float({{width}})
    _C = {{color|json}}

    # 用 Bezier 画一条 S 形
    bpy.ops.curve.primitive_bezier_curve_add(location=_LOC)
    cv = bpy.context.object; cv.name = _NAME + '_curve'
    cv.data.dimensions = '2D'
    cv.data.bevel_depth = _W * 0.5
    cv.data.bevel_resolution = 4
    cv.data.fill_mode = 'BOTH'
    bp = cv.data.splines[0].bezier_points
    bp[0].co = (-_L * 0.5, -_L * 0.2, 0)
    bp[1].co = ( _L * 0.5,  _L * 0.2, 0)
    bp[0].handle_left = (-_L * 0.7, -_L * 0.4, 0)
    bp[0].handle_right = (-_L * 0.2, _L * 0.3, 0)
    bp[1].handle_left = ( _L * 0.2, -_L * 0.3, 0)
    bp[1].handle_right = ( _L * 0.7,  _L * 0.4, 0)

    mat = bpy.data.materials.new(_NAME + '_mat')
    mat.use_nodes = True
    bsdf = mat.node_tree.nodes.get('Principled BSDF')
    if bsdf:
        if 'Base Color' in bsdf.inputs:
            bsdf.inputs['Base Color'].default_value = (_C[0], _C[1], _C[2], 1.0)
        if 'Roughness' in bsdf.inputs:
            bsdf.inputs['Roughness'].default_value = 0.1
        for key in ['Transmission Weight', 'Transmission']:
            if key in bsdf.inputs:
                bsdf.inputs[key].default_value = 0.8
                break
        if 'IOR' in bsdf.inputs:
            bsdf.inputs['IOR'].default_value = 1.33
    cv.data.materials.append(mat)
    print('[apply_template] river_curve 完成: 长 ' + str(_L) + 'm 宽 ' + str(_W) + 'm')
except Exception as _e:
    import traceback; print('[apply_template] river_curve 失败:', _e); traceback.print_exc()

import bpy
try:
    _NAME = {{name|json}}
    _LOC = {{location|json}}
    _S = float({{size}})
    _C = {{color|json}}
    _STR = float({{strength}})

    bpy.ops.mesh.primitive_ico_sphere_add(radius=_S, subdivisions=3, location=_LOC)
    obj = bpy.context.object; obj.name = _NAME
    tex = bpy.data.textures.new(_NAME + '_tex', 'VORONOI')
    tex.noise_scale = 0.5
    dm = obj.modifiers.new('Displace', 'DISPLACE')
    dm.texture = tex
    dm.strength = _STR * _S
    dec = obj.modifiers.new('Dec', 'DECIMATE')
    dec.ratio = 0.5
    bpy.ops.object.shade_smooth()

    mat = bpy.data.materials.new(_NAME + '_mat')
    mat.use_nodes = True
    bsdf = mat.node_tree.nodes.get('Principled BSDF')
    if bsdf:
        if 'Base Color' in bsdf.inputs:
            bsdf.inputs['Base Color'].default_value = (_C[0], _C[1], _C[2], 1.0)
        if 'Roughness' in bsdf.inputs:
            bsdf.inputs['Roughness'].default_value = 0.9
    obj.data.materials.append(mat)
    print('[apply_template] rock_voronoi 完成: r=' + str(_S) + ' strength=' + str(_STR))
except Exception as _e:
    import traceback; print('[apply_template] rock_voronoi 失败:', _e); traceback.print_exc()

import bpy, math
try:
    _NAME = {{name|json}}
    _LOC = {{location|json}}
    _S = float({{size}})
    _K = {{kind|json}}

    color_map = {'white': (0.95, 0.95, 0.95, 0.0, 0.85), 'silver': (0.92, 0.92, 0.94, 0.95, 0.25), 'gold': (1.0, 0.78, 0.30, 0.92, 0.30)}
    c = color_map.get(_K, color_map['white'])

    mat = bpy.data.materials.new(_NAME + '_mat')
    mat.use_nodes = True
    b = mat.node_tree.nodes.get('Principled BSDF')
    if b and 'Base Color' in b.inputs:
        b.inputs['Base Color'].default_value = (c[0], c[1], c[2], 1.0)
    if b and 'Metallic' in b.inputs:
        b.inputs['Metallic'].default_value = c[3]
    if b and 'Roughness' in b.inputs:
        b.inputs['Roughness'].default_value = c[4]

    bpy.ops.mesh.primitive_plane_add(size=_S, location=_LOC)
    obj = bpy.context.object; obj.name = _NAME + '_' + _K
    # 圆形（用 Bevel + Subsurf 让边角圆）
    obj.rotation_euler = (math.radians(90), 0, math.radians(45))
    bpy.ops.object.transform_apply(location=False, rotation=True, scale=False)
    obj.data.materials.append(mat)
    print('[apply_template] studio_reflector 完成: ' + _K + ' size=' + str(_S))
except Exception as _e:
    import traceback; print('[apply_template] studio_reflector 失败:', _e); traceback.print_exc()

import bpy, math
try:
    _NAME = {{name|json}}
    _LOC = {{location|json}}
    _S = float({{size}})

    mat = bpy.data.materials.new(_NAME + '_mat')
    mat.use_nodes = True
    b = mat.node_tree.nodes.get('Principled BSDF')
    if b:
