            if k in b.inputs:
                b.inputs[k].default_value = 0.95
                break
        if 'IOR' in b.inputs:
            b.inputs['IOR'].default_value = 1.49

    # 顶部 plane（产品台面）
    bpy.ops.mesh.primitive_plane_add(size=_S, location=(_LOC[0], _LOC[1], _LOC[2] + _S * 0.6))
