        bpy.ops.mesh.primitive_plane_add(size=1, location=(_LOC[0], _LOC[1] + sy * _S * 0.5, _LOC[2] + _S * 0.3))
        side = bpy.context.object; side.name = _NAME + '_side'
        side.rotation_euler = (math.radians(90), 0, 0)
        side.scale = (_S, _S * 0.6, 1.0)
        bpy.ops.object.transform_apply(location=False, rotation=True, scale=True)
        side.data.materials.append(mat)
    print('[apply_template] studio_product_acrylic 完成')
