import bpy, math, random
try:
    _NAME = {{name|json}}
    _LOC = {{location|json}}
    _N = max(1, int({{count}}))
    _S = float({{size}})
    _C = {{color|json}}

    mat = bpy.data.materials.new(_NAME + '_mat')
    mat.use_nodes = True
    b = mat.node_tree.nodes.get('Principled BSDF')
    if b:
        if 'Base Color' in b.inputs:
            b.inputs['Base Color'].default_value = (_C[0], _C[1], _C[2], 1.0)
        if 'Roughness' in b.inputs:
            b.inputs['Roughness'].default_value = 0.05
        for k in ['Transmission Weight', 'Transmission']:
            if k in b.inputs:
                b.inputs[k].default_value = 0.85
                break
        if 'IOR' in b.inputs:
            b.inputs['IOR'].default_value = 1.55
        # 微自发光
        if 'Emission' in b.inputs:
            b.inputs['Emission'].default_value = (_C[0], _C[1], _C[2], 1.0)
        elif 'Emission Color' in b.inputs:
            b.inputs['Emission Color'].default_value = (_C[0], _C[1], _C[2], 1.0)
        if 'Emission Strength' in b.inputs:
            b.inputs['Emission Strength'].default_value = 1.0

    for i in range(_N):
        ang = i * 2 * math.pi / _N + random.random() * 0.3
        r = random.random() * _S * 0.7
        x = _LOC[0] + math.cos(ang) * r
        y = _LOC[1] + math.sin(ang) * r
        h = _S * (1.0 + random.random() * 1.0)
        bpy.ops.mesh.primitive_cone_add(radius1=_S * 0.12 * (0.7 + random.random() * 0.6), radius2=_S * 0.04, depth=h, vertices=6, location=(x, y, _LOC[2] + h * 0.5))
        cr = bpy.context.object; cr.name = _NAME + '_' + str(i + 1)
        cr.rotation_euler = ((random.random() - 0.5) * 0.4, (random.random() - 0.5) * 0.4, random.random() * math.pi)
        cr.data.materials.append(mat)
    print('[apply_template] crystal_cluster 完成: ' + str(_N) + ' 根水晶')
except Exception as _e:
    import traceback; print('[apply_template] crystal_cluster 失败:', _e); traceback.print_exc()

