import bpy
try:
    _NAME = {{name|json}}
    _LOC = {{location|json}}
    _L = float({{length}})
    _CC = {{crystal_color|json}}

    wood_mat = bpy.data.materials.new(_NAME + '_wood')
    wood_mat.use_nodes = True
    b = wood_mat.node_tree.nodes.get('Principled BSDF')
    if b and 'Base Color' in b.inputs:
        b.inputs['Base Color'].default_value = (0.28, 0.18, 0.12, 1.0)
    if b and 'Roughness' in b.inputs:
        b.inputs['Roughness'].default_value = 0.7

    crystal_mat = bpy.data.materials.new(_NAME + '_crystal')
    crystal_mat.use_nodes = True
    bc = crystal_mat.node_tree.nodes.get('Principled BSDF')
    if bc:
        if 'Base Color' in bc.inputs:
            bc.inputs['Base Color'].default_value = (_CC[0], _CC[1], _CC[2], 1.0)
        if 'Roughness' in bc.inputs:
            bc.inputs['Roughness'].default_value = 0.05
        for k in ['Transmission Weight', 'Transmission']:
            if k in bc.inputs:
                bc.inputs[k].default_value = 0.85
                break
        if 'IOR' in bc.inputs:
            bc.inputs['IOR'].default_value = 1.55
        for k in ['Emission', 'Emission Color']:
            if k in bc.inputs:
                bc.inputs[k].default_value = (_CC[0], _CC[1], _CC[2], 1.0)
                break
        if 'Emission Strength' in bc.inputs:
            bc.inputs['Emission Strength'].default_value = 3.0

    metal_mat = bpy.data.materials.new(_NAME + '_metal')
    metal_mat.use_nodes = True
    bm = metal_mat.node_tree.nodes.get('Principled BSDF')
    if bm and 'Base Color' in bm.inputs:
        bm.inputs['Base Color'].default_value = (0.85, 0.65, 0.30, 1.0)
    if bm and 'Metallic' in bm.inputs:
        bm.inputs['Metallic'].default_value = 0.9
    if bm and 'Roughness' in bm.inputs:
        bm.inputs['Roughness'].default_value = 0.3

    # 杖身
    bpy.ops.mesh.primitive_cylinder_add(radius=0.025, depth=_L, vertices=10, location=(_LOC[0], _LOC[1], _LOC[2] + _L * 0.5))
    body = bpy.context.object; body.name = _NAME + '_body'
    bpy.ops.object.shade_smooth()
    body.data.materials.append(wood_mat)

    # 中段金属环
    bpy.ops.mesh.primitive_torus_add(major_radius=0.03, minor_radius=0.005, major_segments=12, minor_segments=4, location=(_LOC[0], _LOC[1], _LOC[2] + _L * 0.7))
    ring = bpy.context.object; ring.name = _NAME + '_ring'
    bpy.ops.object.shade_smooth()
    ring.data.materials.append(metal_mat)

    # 顶部水晶（cone + 球）
    bpy.ops.mesh.primitive_ico_sphere_add(radius=0.06, subdivisions=2, location=(_LOC[0], _LOC[1], _LOC[2] + _L + 0.05))
    crystal = bpy.context.object; crystal.name = _NAME + '_crystal'
    crystal.scale = (1.0, 1.0, 1.5)
    bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)
    crystal.data.materials.append(crystal_mat)

    # 内置点光
    bpy.ops.object.light_add(type='POINT', location=(_LOC[0], _LOC[1], _LOC[2] + _L + 0.05))
    lt = bpy.context.object; lt.name = _NAME + '_light'
    lt.data.energy = 80
    lt.data.color = (_CC[0], _CC[1], _CC[2])
    print('[apply_template] magic_staff 完成')
except Exception as _e:
    import traceback; print('[apply_template] magic_staff 失败:', _e); traceback.print_exc()
